export function Loading({ text = "Đang tải..." }: { text?: string }) {
  return (
    <div className="flex flex-col items-center justify-center min-h-screen">
      <div className="relative">
        <div className="w-16 h-16 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin"></div>
      </div>
      <p className="mt-4 text-gray-600 font-medium">{text}</p>
    </div>
  );
}

import { Link, useLocation } from 'react-router';
import { usePermission } from '~/hooks/usePermission';
import { getNavigationForUser, type NavigationItem } from '~/utils/navigation';
import { useState } from 'react';
import { ChevronDownIcon, ChevronRightIcon } from '@heroicons/react/24/outline';

/**
 * Permission-based Sidebar Navigation
 * Tự động ẩn/hiện menu items dựa trên quyền của user
 */
export function PermissionBasedSidebar() {
  const location = useLocation();
  const { hasAnyPermission, hasAllPermissions } = usePermission();
  const [expandedItems, setExpandedItems] = useState<string[]>([]);

  // Get navigation items for current user
  const navigationItems = getNavigationForUser(hasAnyPermission, hasAllPermissions);

  const toggleExpanded = (href: string) => {
    setExpandedItems(prev =>
      prev.includes(href)
        ? prev.filter(item => item !== href)
        : [...prev, href]
    );
  };

  const isActive = (href: string) => {
    return location.pathname === href || location.pathname.startsWith(href + '/');
  };

  const renderNavigationItem = (item: NavigationItem, level: number = 0) => {
    const hasChildren = item.children && item.children.length > 0;
    const isExpanded = expandedItems.includes(item.href);
    const active = isActive(item.href);

    return (
      <div key={item.href}>
        {hasChildren ? (
          // Parent item with children
          <button
            onClick={() => toggleExpanded(item.href)}
            className={`
              w-full flex items-center justify-between px-4 py-2 text-sm font-medium rounded-lg
              transition-colors duration-150
              ${active 
                ? 'bg-blue-100 text-blue-700' 
                : 'text-gray-700 hover:bg-gray-100'
              }
              ${level > 0 ? 'ml-4' : ''}
            `}
          >
            <div className="flex items-center">
              {item.icon && <item.icon className="w-5 h-5 mr-3" />}
              <span>{item.name}</span>
            </div>
            {isExpanded ? (
              <ChevronDownIcon className="w-4 h-4" />
            ) : (
              <ChevronRightIcon className="w-4 h-4" />
            )}
          </button>
        ) : (
          // Leaf item without children
          <Link
            to={item.href}
            className={`
              flex items-center px-4 py-2 text-sm font-medium rounded-lg
              transition-colors duration-150
              ${active 
                ? 'bg-blue-100 text-blue-700' 
                : 'text-gray-700 hover:bg-gray-100'
              }
              ${level > 0 ? 'ml-4' : ''}
            `}
          >
            {item.icon && <item.icon className="w-5 h-5 mr-3" />}
            <span>{item.name}</span>
          </Link>
        )}

        {/* Render children if expanded */}
        {hasChildren && isExpanded && (
          <div className="mt-1 space-y-1">
            {item.children!.map(child => renderNavigationItem(child, level + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <nav className="space-y-1 p-4">
      {navigationItems.map(item => renderNavigationItem(item))}
    </nav>
  );
}

/**
 * Usage in MainLayout:
 * 
 * <aside className="sidebar">
 *   <PermissionBasedSidebar />
 * </aside>
 */

import { Navigate } from 'react-router';
import { usePermission } from '~/hooks/usePermission';

interface ProtectedRouteProps {
  children: React.ReactNode;
  requiredPermission?: string;
  requiredPermissions?: string[];
  requireAll?: boolean;
  fallbackPath?: string;
}

/**
 * Component to protect routes based on permissions
 * 
 * Usage:
 * <ProtectedRoute requiredPermission="users.view">
 *   <UsersPage />
 * </ProtectedRoute>
 * 
 * Or multiple permissions:
 * <ProtectedRoute requiredPermissions={['orders.view', 'orders.edit']} requireAll={false}>
 *   <OrdersPage />
 * </ProtectedRoute>
 */
export function ProtectedRoute({
  children,
  requiredPermission,
  requiredPermissions,
  requireAll = false,
  fallbackPath = '/dashboard',
}: ProtectedRouteProps) {
  const { hasPermission, hasAnyPermission, hasAllPermissions } = usePermission();

  // Check single permission
  if (requiredPermission && !hasPermission(requiredPermission)) {
    return <Navigate to={fallbackPath} replace />;
  }

  // Check multiple permissions
  if (requiredPermissions) {
    const hasAccess = requireAll
      ? hasAllPermissions(requiredPermissions)
      : hasAnyPermission(requiredPermissions);

    if (!hasAccess) {
      return <Navigate to={fallbackPath} replace />;
    }
  }

  return <>{children}</>;
}

/**
 * Higher-order component to wrap route components with permission check
 */
export function withPermission(
  Component: React.ComponentType,
  requiredPermission: string | string[],
  requireAll = false
) {
  return function ProtectedComponent(props: any) {
    const permissions = Array.isArray(requiredPermission) ? requiredPermission : [requiredPermission];

    return (
      <ProtectedRoute
        requiredPermissions={permissions}
        requireAll={requireAll}
      >
        <Component {...props} />
      </ProtectedRoute>
    );
  };
}
